.step-indicator {
    align-items: flex-start;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 80px;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.875rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step.dimmed .step-circle {
    opacity: 0.5;
}

.step-label {
    margin-top: 0.5rem;
    font-size: 0.75rem;
    text-align: center;
    color: #6c757d;
    max-width: 90px;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step.dimmed .step-label {
    opacity: 0.5;
}

