{"file_text": "<div class="step-indicator d-flex justify-content-between mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var stepIndex = i;
        var isCompleted = CompletedSteps.Contains(stepIndex);
        var isCurrent = stepIndex == CurrentStep;
        var isClickable = isCompleted;

        <div class="step @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(!isCurrent && !isCompleted ? "dimmed" : "")"
             @onclick="() => HandleStepClick(stepIndex)"
             role="@(isClickable ? "button" : "")"
             style="@(isClickable ? "cursor: pointer;" : "")">
            <div class="step-circle">
                @if (isCompleted)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </div>
            <div class="step-label">@StepNames[stepIndex]</div>
        </div>

        @if (i < StepNames.Length - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(i) ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter] public int CurrentStep { get; set; }
