@page "/apply"
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (submittedId is not null)
    {
        <div class="text-center py-5">
            <div class="alert alert-success d-inline-block px-5 py-4">
                <h4 class="alert-heading">Application Submitted!</h4>
                <p>Your application has been received successfully.</p>
                <hr />
                <p class="mb-0">Your application ID is: <strong class="fs-4">@submittedId</strong></p>
            </div>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps"
                       StepNames="stepNames" OnStepClicked="GoToStep" />

        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo" OnNext="() => AdvanceStep(1)" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="() => AdvanceStep(2)" OnBack="() => GoToStep(0)" />
                break;
            case 2:
                <ReferencesStep References="references"
                                OnNext="() => AdvanceStep(3)" OnBack="() => GoToStep(1)" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="@coverLetter"
                                 OnNext="HandleCoverLetterNext" OnBack="() => GoToStep(2)" />
                break;
            case 4:
                <ReviewStep Personal="personalInfo" WorkEntries="workEntries"
                            References="references" CoverLetter="@coverLetter"
                            OnEditStep="GoToStep" OnBack="() => GoToStep(3)"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int currentStep;
    private readonly HashSet<int> completedSteps = new();
    private int? submittedId;

    private readonly string[] stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private readonly PersonalInfoModel personalInfo = new();
    private readonly List<WorkEntryModel> workEntries = [new()];
    private readonly List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void AdvanceStep(int nextStep)
    {
        completedSteps.Add(currentStep);
        currentStep = nextStep;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        AdvanceStep(4);
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        submittedId = await ApplicationService.SubmitApplicationAsync(application);
    }
}

